mapper.select:
SELECT category_id, COUNT(*) AS resource_count
FROM info_resource
WHERE status = '0'
  AND del_flag = '0'

    AND (title LIKE CONCAT('%', #{keyword}, '%')
        OR description LIKE CONCAT('%', #{keyword}, '%')
        OR original_name LIKE CONCAT('%', #{keyword}, '%'))


    AND preview_type = #{previewType}


    AND create_time >= #{uploadedSince}


    AND file_size >= #{minFileSize}


    AND file_size < #{maxFileSize}

GROUP BY category_id
